import{_ as t,a as n}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as a,c as r,a2 as d}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"WebDAV-Zugriff einrichten","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/Safety/webdav-site-access.md","filePath":"de-DE/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),l={name:"de-DE/Safety/webdav-site-access.md"};function s(o,e,h,u,c,g){return a(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="webdav-zugriff-einrichten" tabindex="-1">WebDAV-Zugriff einrichten <a class="header-anchor" href="#webdav-zugriff-einrichten" aria-label="Permalink to &quot;WebDAV-Zugriff einrichten&quot;">​</a></h1><p>ImgBed kann WebDAV-Zugriff bereitstellen, damit Dateien über den Dateimanager oder kompatible Clients geprüft werden können.</p><h2 id="einsatzfalle" tabindex="-1">Einsatzfälle <a class="header-anchor" href="#einsatzfalle" aria-label="Permalink to &quot;Einsatzfälle&quot;">​</a></h2><ul><li>Dateien unter Windows oder macOS ansehen.</li><li>Dateien mit einem WebDAV-Client organisieren.</li><li>Auf gespeicherte Dateien außerhalb des Adminbereichs zugreifen.</li></ul><h2 id="verbindung-unter-windows-11" tabindex="-1">Verbindung unter Windows 11 <a class="header-anchor" href="#verbindung-unter-windows-11" aria-label="Permalink to &quot;Verbindung unter Windows 11&quot;">​</a></h2><ol><li>Öffne den Datei-Explorer.</li><li>Klicke mit der rechten Maustaste auf <code>Dieser PC</code>.</li><li>Wähle <code>Netzwerkadresse hinzufügen</code>.</li><li>Gib die WebDAV-URL ein.</li><li>Trage Benutzername und Passwort ein.</li><li>Prüfe, ob der Inhalt wie ein Ordner geöffnet wird.</li></ol><p><img src="'+t+'" alt="WebDAV unter Windows 11" loading="lazy"></p><p>Bei erfolgreicher Verbindung erscheint der Inhalt im Explorer.</p><p><img src="'+n+'" alt="WebDAV-Anzeige unter Windows" loading="lazy"></p><h2 id="zugangsdaten" tabindex="-1">Zugangsdaten <a class="header-anchor" href="#zugangsdaten" aria-label="Permalink to &quot;Zugangsdaten&quot;">​</a></h2><p>Verwende die in ImgBed konfigurierten WebDAV-Zugangsdaten. Für mehr Sicherheit ist ein Konto mit eingeschränkten Rechten besser als ein gemeinsam genutztes Hauptkonto.</p><h2 id="wenn-die-verbindung-fehlschlagt" tabindex="-1">Wenn die Verbindung fehlschlägt <a class="header-anchor" href="#wenn-die-verbindung-fehlschlagt" aria-label="Permalink to &quot;Wenn die Verbindung fehlschlägt&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Punkt</th><th>Prüfung</th></tr></thead><tbody><tr><td>URL</td><td>Enthält <code>https://</code> und ist die korrekte WebDAV-Adresse</td></tr><tr><td>Zugangsdaten</td><td>Benutzername und Passwort stimmen</td></tr><tr><td>Rechte</td><td>Lesen und Schreiben im Zielordner erlaubt</td></tr><tr><td>Client</td><td>Windows oder WebDAV-Client blockiert die Verbindung nicht</td></tr></tbody></table><p>Wenn nur die Kapazitätsabfrage fehlschlägt, Uploads aber funktionieren, liefert der WebDAV-Server möglicherweise keine Quota-Informationen.</p>',14)])])}const p=i(l,[["render",s]]);export{m as __pageData,p as default};
